<script>

    // import config
    import { APP_NAME, APP_VERSION, DEFAULT_SERVER, ENDPOINT_DESTROY_SID } from './config.js';
    const server = DEFAULT_SERVER;

    // import pages
    import Dashboard from './pages/Dashboard/Dashboard.svelte';
    import Logbooks from './pages/Logbooks/Logbooks.svelte';
    import Login from './pages/Login.svelte';
    import Account from './pages/Account.svelte';

    // import components
    import Loader from './components/Loader.svelte';

    // page navigation logic
    let signed_in = false;
    let current_page = 'dashboard';
    
    // variables
    import { freeze, frozen, unfreeze } from '../../meza-libraries/utils/web/svelte-stores.js';
    let _frozen = false;
    frozen.subscribe(value => {
        _frozen = value;
    })

    // import libs
    import { reqDELETE } from '../../meza-libraries/http/web/http.js';

</script>

<!-- Overlay to stop click action -->
{#if _frozen}
    <Loader/>
{/if}


<div id="navbar">
    <h1 id="title">{APP_NAME}</h1>
    <p id="version" >{`v${APP_VERSION}`}</p>

    {#if signed_in}
    <div id="container-button">
        <button class={current_page === 'dashboard' ? 'selected' : ''} on:click={() => {
            current_page = 'dashboard';
        }}>
            Dashboard
        </button>
        <button class={current_page === 'logbooks' ? 'selected' : ''} on:click={() => {
            current_page = 'logbooks';
        }}>
            Logbooks
        </button>
        <button class={current_page === 'account' ? 'selected' : ''} on:click={() => {
            current_page = 'account';
        }}>
            Account
        </button>
        <button on:click={async () => {

            // send request to delete sid from server
            freeze();
            await reqDELETE(server, ENDPOINT_DESTROY_SID);
            unfreeze();

            current_page = 'dashboard';
            signed_in = false;
        }}>
            Sign out
        </button>
    </div>
    {/if}   

</div>



<main>
    {#if signed_in}
        {#if current_page === 'dashboard'}
            <Dashboard/>
        {:else if current_page === 'logbooks'}
            <Logbooks/>
        {:else if current_page === 'account'}
            <Account/>
        {/if}
    {:else}
        <Login bind:signed_in={signed_in}/>
    {/if}
</main>


