<script>
    
    // properties
    export let image;
    export let branchIdFilter;
    export let openImageBox;
    export let table_templates;
    
    // DOM elements
    let container;
    let canvas_image, canvas_cells;

    // import libs
    import { onMount } from 'svelte';
    import { dateToFormattedString } from '../../../../../meza-libraries/gen/datetime.js';
    import { reqPUT } from '../../../../../meza-libraries/http/web/http.js';
    import { isNumber, isObject } from '../../../../../meza-libraries/gen/datatype.js';
    import { freeze, unfreeze } from '../../../../../meza-libraries/utils/web/svelte-stores.js';
    import { reproject, saveCells } from '../libs.js';
    import { set_box_border_color, set_box_thumbnail, set_box_cells, get_rotated_corners } from './scripts.js';
    import { IMAGE_STATUS } from '../../../../../meza-imageprocessor/config/config-images.js';

    // import config
    import { DEFAULT_SERVER, ENDPOINT_IMAGE } from '../../../config.js';
    const server = DEFAULT_SERVER;

    // unpack
    const image_id = image['id'];
    const branch_name = image['branch_name'];
    const created_at = image['created_at'];
    let table_template_id = -1;
    if (isNumber(image['table_template_id']) && image['approved'] !== false) {
        table_template_id = image['table_template_id'];
    }

    const nbr_bubble = image['nbr_bubble'];
    const nbr_bubble_decoded = image['nbr_bubble_decoded'];
    const nbr_float = image['nbr_float'];
    const nbr_float_decoded = image['nbr_float_decoded'];
    const nbr_integer = image['nbr_integer'];
    const nbr_integer_decoded = image['nbr_integer_decoded'];

    // sum
    let percentage_cells_decoded = 0.0;
    const nbr_cells_decoded = nbr_bubble_decoded + nbr_integer_decoded + nbr_float_decoded;
    const nbr_cells = nbr_bubble + nbr_integer + nbr_float;
    if (nbr_cells > 0) {
        percentage_cells_decoded = (100.0 * nbr_cells_decoded) / (1.0 * nbr_cells);
        percentage_cells_decoded = Math.round( 100.0 * percentage_cells_decoded ) / 100.0;
    }

    // format date to yyyy-mm-dd
    const date_formatted = dateToFormattedString(new Date(created_at));


    async function updateRotation() {

        // if we have a table template
        if ( isNumber(image['table_template_id']) ) {

            // get rotated corners
            const corners_rotated = get_rotated_corners( image )

            // save
            await saveCells( image_id, table_templates, corners_rotated )
        }
        
        // --------------------------------------------------------------------------------------------------------------

        // update rotation
        image['rotation'] = (image['rotation'] + 90) % 360;

        // build payload
        const payload = {
            'rotation': image['rotation'],
            'status': IMAGE_STATUS['CUTTING']
        }

        // set freeze flag
        const results = await reqPUT(server, ENDPOINT_IMAGE(image_id), payload)

        // check
        if (results === undefined || results === null || !isObject(results) || !isNumber(results['status'])){
            console.error(`Could not update the rotation.`, 'error');
            return;
        }

        // --------------------------------------------------------------------------------------------------------------

        // redraw
        await set_box_thumbnail( image, table_templates );
    }


    onMount(() => {

        // set intersection observer
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(async (entry) => {

                // check
                if (!entry.isIntersecting) return;

                // start a timer that will check in 1 second if the image is still in the viewport
                await new Promise(r => setTimeout(r, 500));

                // check if it still intersects with the viewport
                const bbox = entry.target.getBoundingClientRect();
                if (bbox.bottom < 0 || bbox.top > window.innerHeight) return;
                
                // remove observer
                observer.unobserve(entry.target);

                // set thumbnail
                await set_box_thumbnail( image, table_templates );
            });
        }, { root: null, rootMargin: '0px', threshold: 0.0 });

        // observe
        observer.observe(container);

        // set border color
        set_box_border_color( image );
    });

</script>


<!-- svelte-ignore a11y-click-events-have-key-events -->
<div style="display: {branchIdFilter === null || branchIdFilter === image['branch_id'] ? 'flex' : 'none'}" data-image_id={image_id} data-table_template_id={table_template_id} bind:this={container} class="imageContainer" on:click={ () => {
        openImageBox(image_id);
    }}>
    <canvas class="canvas-image" bind:this={canvas_image}></canvas>
    <canvas style="display:none;" class="canvas-cells" bind:this={canvas_cells}></canvas>
    <div class="imageCaption">
        <p>{date_formatted}</p>
        <p>{branch_name}</p>
        <p>Decoded: {percentage_cells_decoded}%</p>
    </div>
    <button class="rotate" on:click={ async (event) => {
        event.stopPropagation();
        freeze();
        await updateRotation();
        unfreeze();
    }}>Rotate</button>
</div>



