// import config
import { ENDPOINT_CELLS, DEFAULT_SERVER } from '../../../config.js';
const server = DEFAULT_SERVER;

// import lib
import * as d3 from 'd3';
import { promptForCellValue } from './prompt.js';
import { isString, isStringNonEmpty, isArrayNonEmpty, isNumber, isObject } from '../../../../../meza-libraries/gen/datatype.js';
import { reqPUT } from '../../../../../meza-libraries/http/web/http.js';
import { getCornerPoints, reproject } from '../libs.js';

// config
const ID_CANVAS_CONTAINER = 'canvas-container';
const ID_CANVAS_IMG = 'img-canvas';
const ID_CANVAS_OVERLAY = 'overlay-canvas';
const ID_CANVAS_VALUE = 'value-canvas';
const ID_CANVAS_SKETCH = 'sketch-canvas';


// ------- STYLING -------
const textBottomPadding = 2
const textFontStyle = 'bold 14px Arial'
const overlayBlackout_color = 'black';
const overlayBlackout_opacity = '1.0';
const overlayFailed_color = 'red';
const overlayFailed_opacity = '0.2';
const overlayNull_color = 'orange';
const overlayNull_opacity = '0.2';
const overlayString_color = 'SaddleBrown';
const overlayString_opacity = '0.2';
const overlayEmpty_color = 'SkyBlue';
const overlayEmpty_opacity = '0.4';
const overlayDecoded_color = 'green';
const overlayDecoded_opacity = '0.2';
const overlayOnMouseOver_color = 'white';
const overlayOnMouseOver_opacity = '0.8';

const color_main = '#085287';
const corner_circle_radius = 5;
// -----------------------


/*
    Compute the resize factor of the image to fit the canvas
*/
export function computeImageResizeFactor(image_width, image_height) {
    
    // init
    let offsetLeft, offsetTop, width, height, resizeFactor;

    // get the canvas container dimensions
    const { clientWidth, clientHeight } = document.getElementById(ID_CANVAS_CONTAINER);

    // compute the resize factor
    if (image_width < clientWidth && image_height < clientHeight) {
        
        // if smaller than canvas
        offsetLeft = Math.round((clientWidth - image_width) / 2.0)
        offsetTop = Math.round((clientHeight - image_height) / 2.0)
        width = image_width;
        height = image_height;
        resizeFactor = 1.0;

    } else {

        // if bigger than canvas
        resizeFactor = Math.min(clientWidth / (1.0 * image_width), clientHeight / (1.0 * image_height))
        width = Math.floor(image_width * resizeFactor)
        height = Math.floor(image_height * resizeFactor)
        offsetLeft = Math.round((clientWidth - width) / 2.0)
        offsetTop = Math.round((clientHeight - height) / 2.0)
    }

    return {
        'offsetLeft': offsetLeft,
        'offsetTop': offsetTop,
        'width': width,
        'height': height,
        'resizeFactor': resizeFactor
    }
}


/*
    Init the dimensions of the canvas
*/
export function init(image_width, image_height, image_resized_width, image_resized_height) {

    // Get the canvas
    const imgCanvas = document.getElementById(ID_CANVAS_IMG);
    const overlayCanvas = document.getElementById(ID_CANVAS_OVERLAY);
    const valueCanvas = document.getElementById(ID_CANVAS_VALUE);
    const sketchCanvas = document.getElementById(ID_CANVAS_SKETCH);

    // Set canvas style dimensions
    imgCanvas.width = image_width;
    imgCanvas.height = image_height;

    // resize the canvas
    imgCanvas.style.width = `${image_resized_width}px`;
    imgCanvas.style.height = `${image_resized_height}px`;
    overlayCanvas.width = image_resized_width;
    overlayCanvas.height = image_resized_height;
    valueCanvas.width = image_resized_width;
    valueCanvas.height = image_resized_height;
    sketchCanvas.width = image_resized_width;
    sketchCanvas.height = image_resized_height;
}


/*
    Clear the canvas
*/
export function clear() {

    // Get the canvas
    const imgCanvas = document.getElementById(ID_CANVAS_IMG);
    const overlayCanvas = document.getElementById(ID_CANVAS_OVERLAY);
    const valueCanvas = document.getElementById(ID_CANVAS_VALUE);
    const sketchCanvas = document.getElementById(ID_CANVAS_SKETCH);

    // Get the contexts
    const imgContext = imgCanvas.getContext('2d');
    const overlayContext = overlayCanvas.getContext('2d');
    const valueContext = valueCanvas.getContext('2d');
    const sketchContext = sketchCanvas.getContext('2d');

    // clear the canvas
    imgContext.clearRect(0, 0, imgCanvas.width, imgCanvas.height);
    overlayContext.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);
    valueContext.clearRect(0, 0, valueCanvas.width, valueCanvas.height);   
    sketchContext.clearRect(0, 0, sketchCanvas.width, sketchCanvas.height); 

    // clear the svgbox
    d3.select('#svgbox').selectAll('*').remove();

    // clear event listeners
    d3.select(valueCanvas).on('mousedown', null);
    d3.select(valueCanvas).on('mouseup', null);
    d3.select(valueCanvas).on('mousemove', null);
    d3.select(valueCanvas).on('mouseout', null);
    d3.select(valueCanvas).on('mouseover', null);
}


// --- Draw the overlay ---
export function renderOverlay (rectangles) {

    // Get the canvas
    const overlayCanvas = document.getElementById(ID_CANVAS_OVERLAY);

    // Get the context
    const overlayContext = overlayCanvas.getContext('2d');

    // clear the canvas
    overlayContext.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);

    for (let i = 0; i < rectangles.length; i++) {

        // grab data
        const { value, data_type } = rectangles[i];

        // skip if
        if (data_type === undefined || data_type === null || data_type === 'info') continue;

        // Make path
        overlayContext.beginPath()
        overlayContext.moveTo(rectangles[i]['tl_x'], rectangles[i]['tl_y'])
        overlayContext.lineTo(rectangles[i]['tr_x'], rectangles[i]['tr_y'])
        overlayContext.lineTo(rectangles[i]['br_x'], rectangles[i]['br_y'])
        overlayContext.lineTo(rectangles[i]['bl_x'], rectangles[i]['bl_y'])
        overlayContext.closePath();

        if (data_type === 'blackout') {
            // failed
            overlayContext.globalAlpha = overlayBlackout_opacity
            overlayContext.fillStyle = overlayBlackout_color
            overlayContext.fill()

        } else if (value === 'failed') {
            // failed
            overlayContext.globalAlpha = overlayFailed_opacity
            overlayContext.fillStyle = overlayFailed_color
            overlayContext.fill()

        } else if (value === '') {
            // empty
            overlayContext.globalAlpha = overlayEmpty_opacity
            overlayContext.fillStyle = overlayEmpty_color
            overlayContext.fill()

        } else if (isStringNonEmpty(value)){
            // decoded
            overlayContext.globalAlpha = overlayDecoded_opacity
            overlayContext.fillStyle = overlayDecoded_color
            overlayContext.fill()

        }else if (data_type === 'string') {
            // string
            overlayContext.globalAlpha = overlayString_opacity
            overlayContext.fillStyle = overlayString_color
            overlayContext.fill()

        }else if (value === undefined || value === null) {
            // being decoded
            overlayContext.globalAlpha = overlayNull_opacity
            overlayContext.fillStyle = overlayNull_color
            overlayContext.fill()
        }
    }
}


// --- Draw the value ---
export function renderValue (rectangles_to_render) {

    // Get the canvas
    const valueCanvas = document.getElementById(ID_CANVAS_VALUE);

    // Get the context
    const valueContext = valueCanvas.getContext('2d')    

    // clear Overlay
    valueContext.clearRect(0, 0, valueCanvas.width, valueCanvas.height);

    // validate
    if (!isArrayNonEmpty(rectangles_to_render)) return;

    // go through rectangles
    for (let i = 0; i < rectangles_to_render.length; i++) {

        // grab data
        const { value, data_type, tl_x, tl_y, tr_x, tr_y, br_x, br_y, bl_x, bl_y } = rectangles_to_render[i];

        // skip if
        if (value === undefined || data_type === undefined || data_type === null ||
                data_type === 'info' || data_type == 'blackout') continue;

        // center point
        const ave_x0 = (tl_x + bl_x) / 2.0
        const ave_x1 = (tr_x + br_x) / 2.0
        const c_x = Math.round(ave_x0 + (ave_x1 - ave_x0) / 2.0)
        const bottom_y = Math.round((bl_y + br_y) / 2.0)

        // Make path
        valueContext.beginPath()
        valueContext.moveTo(tl_x, tl_y)
        valueContext.lineTo(tr_x, tr_y)
        valueContext.lineTo(br_x, br_y)
        valueContext.lineTo(bl_x, bl_y)
        valueContext.closePath()

        // Draw Rectangle
        valueContext.globalAlpha = overlayOnMouseOver_opacity;
        valueContext.fillStyle = (value === 'failed') ? 'red' : overlayOnMouseOver_color;
        valueContext.fill()

        // Draw Text
        if (value === null) continue;
        valueContext.font = textFontStyle
        valueContext.fillStyle = 'black'
        valueContext.textAlign = 'center'
        valueContext.fillText(value, c_x, bottom_y - textBottomPadding);
    }
}


function is_point_inside_polygon(pt, corners) {

    // init
    let inside = false;

    // unnest point
    const [x, y] = pt;

    // check
    for (var i = 0, j = corners.length - 1; i < corners.length; j = i++) {
        var xi = corners[i][0], yi = corners[i][1];
        var xj = corners[j][0], yj = corners[j][1];

        var intersect = ((yi > y) != (yj > y))
            && (x < (xj - xi) * (y - yi) / (yj - yi) + xi);
        if (intersect) inside = !inside;
    }

    return inside;
}


async function updateCells(image_id, cells, successAction){

    // ask user for a new value
    const value = await promptForCellValue(image_id, cells);

    // check
    if (!isString(value)) return;

    // create payload for request
    const payload = {
        'rect_ids': cells.map(cell => `${cell['rect_id']}`),
        'image_id': image_id,
        'value': value
    }

    // send request
    const results = await reqPUT(server, ENDPOINT_CELLS, payload);

    // check response
    if (!isObject(results)) return;

    // update displayed data
    successAction(value);
}


// Takes the event as input and gives the clicked rect
function getPointedRectId (mousePos, rectangles) {

    // Init vars
    let rect_id = -1

    // grab x, y of mouse position
    const x = mousePos.layerX;
    const y = mousePos.layerY;

    // Go through rectangles
    for (const rectangle of rectangles) {

        // grab corners
        const rect_tl = [+rectangle['tl_x'], +rectangle['tl_y']];
        const rect_tr = [+rectangle['tr_x'], +rectangle['tr_y']];
        const rect_br = [+rectangle['br_x'], +rectangle['br_y']];
        const rect_bl = [+rectangle['bl_x'], +rectangle['bl_y']];
        const corners = [rect_tl, rect_tr, rect_br, rect_bl];

        // check if point is inside
        if (is_point_inside_polygon([x, y], corners)) {
            rect_id = rectangle['rect_id']
            break
        }
    }

    return rect_id
}


function filter_rectangles_by_rect_id(rect_ids, rectangles){

    if (isNumber(rect_ids)){
        return rectangles.filter(r => +r['rect_id'] === +rect_ids);
    }

    if (isArrayNonEmpty(rect_ids)){
        return rectangles.filter(r => rect_ids.map(r_id => +r_id).includes(+r['rect_id']));
    }

    if (rect_ids instanceof Set) {
        return rectangles.filter(r => rect_ids.has(+r['rect_id']));
    }

    return [];
}


export function setInteractivity(image_id, rectangles){
    
    // Get the canvas
    const valueCanvas = document.getElementById(ID_CANVAS_VALUE);

    // init variables
    let mouseDown = 0;
    let rect_ids = new Set();

    d3.select(valueCanvas).on('mousedown', (e) => {
        mouseDown += 1;

        // Get pointed rect
        const rect_id = getPointedRectId(e, rectangles)

        // if no rect selected
        if (+rect_id === -1) return;

        // add
        rect_ids.clear();
        rect_ids.add(+rect_id);
    })

    d3.select(valueCanvas).on('mousemove', (e) => {

        // Get pointed rect
        const rect_id = getPointedRectId(e, rectangles)

        // if no rect selected
        if (+rect_id === -1) return

        // if mouse is not pressed
        if (mouseDown <= 0) {

            // get rects
            const m_rects = filter_rectangles_by_rect_id(rect_id, rectangles);

            // show value
            renderValue(m_rects);

            // stop
            return;
        }

        // add
        rect_ids.add(+rect_id);

        // get the rects
        const m_rects = filter_rectangles_by_rect_id(rect_ids, rectangles);

        // Render
        renderValue(m_rects);
    })

    d3.select(valueCanvas).on('mouseup', () => {

        // freeze the rect ids
        const m_rect_ids = [...rect_ids];

        // select the rectangles for these rect_ids
        const m_rects = filter_rectangles_by_rect_id(m_rect_ids, rectangles);

        // reset
        mouseDown = 0;
        rect_ids.clear();

        // clear overlay
        renderValue();

        // On success
        const successAction = (newvalue) => {

            // update values
            rectangles.forEach(rectangle => {
                if (!m_rect_ids.includes(+rectangle['rect_id'])) return;
                rectangle['value'] = newvalue;
            })

            // Redraw canvas
            renderOverlay(rectangles)
            renderValue(m_rect_ids)
        }

        // Modify
        updateCells(image_id, m_rects, successAction)
    })
}


export function project_rectangles(table_template) {

    // Get DOM element
    const imgCanvas = document.getElementById(ID_CANVAS_IMG);
    
    // Get the canvas width and height
    const image_width = imgCanvas.width;
    const image_height = imgCanvas.height;

    // compute image position and size in relation to the canvas
    const { offsetTop, offsetLeft } = computeImageResizeFactor(image_width, image_height);

    // get the circles position from the svg
    const svg = d3.select('#svgbox');
    const circles = svg.selectAll('circle').nodes();
    const corners = circles.map(circle => [circle.getAttribute('cx') - offsetLeft, circle.getAttribute('cy') - offsetTop]);

    // check that we have
    if (corners === undefined || corners === null || !Array.isArray(corners) || corners.length !== 4) {
        console.log('Error: we need 4 corners');
        return;
    }

    // get the corners
    const [tl_x, tl_y] = corners[0];
    const [tr_x, tr_y] = corners[1];
    const [br_x, br_y] = corners[2];
    const [bl_x, bl_y] = corners[3];

    // deep copy rectangles
    // [ { x0, h0, w0, h0 }, { x1, h1, w1, h1 }, ...}]
    const rectangles = JSON.parse(JSON.stringify(table_template.rectangles));

    // get the width and height of the rectangles
    const width = Math.max(...rectangles.map(rectangle => rectangle.w + rectangle.x0));
    const height = Math.max(...rectangles.map(rectangle => rectangle.h + rectangle.y0));

    // projection matrix
    const src_points = [0, 0, width, 0, width, height, 0, height];
    const dst_points = [tl_x, tl_y, tr_x, tr_y, br_x, br_y, bl_x, bl_y];

    // points
    const points = rectangles.map(rectangle => {

        // unpack
        const x = rectangle.x0;
        const y = rectangle.y0;
        const w = rectangle.w;
        const h = rectangle.h;

        return {
            tl_x: x,
            tl_y: y,
            tr_x: x + w,
            tr_y: y,
            br_x: x + w,
            br_y: y + h,
            bl_x: x,
            bl_y: y + h
        }
    });

    // project
    const rectangles_projected = reproject(src_points, dst_points, points);

    // set other attributes
    rectangles_projected.forEach((rectangle, i) => {

        // other
        const rect_id = rectangles[i].id;
        const data_type = rectangles[i].data_type;
        const opts = rectangles[i].opts;

        // set
        rectangle.rect_id = rect_id;
        rectangle.data_type = data_type;
        rectangle.opts = opts;
    });

    // return
    return rectangles_projected;
}


export function draw_table_template(table_template, cells, image_id) {

    // draw the points
    const sketchCanvas = document.getElementById(ID_CANVAS_SKETCH);
    const sketchContext = document.getElementById(ID_CANVAS_SKETCH).getContext('2d');
    sketchContext.clearRect(0, 0, sketchCanvas.width, sketchCanvas.height); 

    // check input variables
    if (table_template === undefined || table_template === null) {
        return;
    }

    // get the reprojected rectangles
    const rectangles_proj = project_rectangles(table_template);
    
    // draw all rectangles
    rectangles_proj.forEach(rectangle => {
        sketchContext.beginPath();
        sketchContext.strokeStyle = color_main;
        sketchContext.lineWidth = 1;
        sketchContext.moveTo(rectangle['tl_x'], rectangle['tl_y']);
        sketchContext.lineTo(rectangle['tr_x'], rectangle['tr_y']);
        sketchContext.lineTo(rectangle['br_x'], rectangle['br_y']);
        sketchContext.lineTo(rectangle['bl_x'], rectangle['bl_y']);
        sketchContext.closePath();
        sketchContext.stroke();
    });
    
    // render
    renderOverlay(rectangles_proj);

    // stop here if no input
    if (cells === undefined || cells === null || !Array.isArray(cells)) return;
    if (!isString(image_id)) return;

    // map cell values, by id 
    const cells_value_map = {};
    cells.forEach(cell => {
        cells_value_map[cell['rect_id']] = cell['value']
    });

    // set values
    rectangles_proj.forEach(rectangle => {
        
        // get rect_id
        const rect_id = rectangle['rect_id'];
        
        // set value
        rectangle['value'] = cells_value_map[rect_id];
    });

    // rerender
    renderOverlay(rectangles_proj);
    renderValue();

    // set interactivity
    setInteractivity(image_id, rectangles_proj);
}


export function run( image, table_template, rectangles, asset, callback_drag, callback_end ) {

    // deep copy the input variables
    image = JSON.parse(JSON.stringify(image));
    rectangles = isArrayNonEmpty(rectangles) ? JSON.parse(JSON.stringify(rectangles)) : null;

    // get asset dimension
    const image_width = asset.width;
    const image_height = asset.height;

    // Get the canvas container dimensions
    const { clientWidth, clientHeight } = document.getElementById(ID_CANVAS_CONTAINER);

    // compute image position and size in relation to the canvas
    const { offsetTop, offsetLeft, width, height, resizeFactor } = computeImageResizeFactor(image_width, image_height);

    // init the canvas
    init(image_width, image_height, width, height);

    // clear the canvas
    clear();

    // get DOM elements
    const imgCanvas = document.getElementById(ID_CANVAS_IMG);
    const imgContext = imgCanvas.getContext('2d');

    // draw image
    imgContext.drawImage(asset, 0, 0, image_width, image_height);

    // ----------------------------------------------------------------------------------------------------
    // ----------------------------------------------------------------------------------------------------
    // ----------------------------------------------------------------------------------------------------

    // init 4 corners in the middle of the image
    let corners = [
        [image_width * resizeFactor / 4, image_height * resizeFactor / 4],
        [image_width * resizeFactor * 3 / 4, image_height * resizeFactor / 4],
        [image_width * resizeFactor * 3 / 4, image_height * resizeFactor * 3 / 4],
        [image_width * resizeFactor / 4, image_height * resizeFactor * 3 / 4]
    ];

    // append the corners as d3 circles
    const svg = d3.select('#svgbox');
    svg.selectAll('circle')
        .data(corners)
        .enter()
        .append('circle')
        .attr('cx', d => d[0])
        .attr('cy', d => d[1])
        .attr('r', corner_circle_radius)
        .attr('fill', color_main)
        .attr('stroke', color_main)
        .attr('stroke-width', 1)
        .attr('pointer-events', 'auto')
        .attr('cursor', 'pointer')
        .call(d3.drag()
            .on('drag', function(d, i) {

                // update the circle cx, cy attributes
                d3.select(this).
                    attr('cx', d.x).
                    attr('cy', d.y);

                // trigger the drag event
                callback_drag();
            })
            .on('end', function(d, i) {

                // collect the position of each rectangle
                callback_end();
            })
        );

    // ----------------------------------------------------------------------------------------------------
    // ----------------------------------------------------------------------------------------------------
    // ----------------------------------------------------------------------------------------------------

    // if the image was not processed
    if ( !isNumber(image['table_template_id']) || !isArrayNonEmpty(rectangles) ) {
        return;
    }

    // resize rectangles
    rectangles.forEach(rectangle => {
        rectangle['tl_x'] = rectangle['tl_x'] * resizeFactor;
        rectangle['tl_y'] = rectangle['tl_y'] * resizeFactor;
        rectangle['tr_x'] = rectangle['tr_x'] * resizeFactor;
        rectangle['tr_y'] = rectangle['tr_y'] * resizeFactor;
        rectangle['br_x'] = rectangle['br_x'] * resizeFactor;
        rectangle['br_y'] = rectangle['br_y'] * resizeFactor;
        rectangle['bl_x'] = rectangle['bl_x'] * resizeFactor;
        rectangle['bl_y'] = rectangle['bl_y'] * resizeFactor;
    });

    // ----------------------------------------------------------------------------------------------------
    // ----------------------------------------------------------------------------------------------------
    // ----------------------------------------------------------------------------------------------------

    // get the corner points
    corners = getCornerPoints(table_template.rectangles, rectangles);

    // update the circles
    svg.selectAll('circle')
        .data(corners)
        .attr('cx', d => {
            const cx = d[0] + offsetLeft;
            if (cx < 0) return corner_circle_radius;
            if (cx > clientWidth) return clientWidth - corner_circle_radius;
            return cx;
        })
        .attr('cy', d => {
            const cy = d[1] + offsetTop;
            if (cy < 0) return corner_circle_radius;
            if (cy > clientHeight) return clientHeight - corner_circle_radius;
            return cy;
        });

    // render
    renderOverlay(rectangles);
    renderValue();

    // set interactivity
    setInteractivity(image['id'], rectangles);

    // draw the table template
    callback_drag();
}
