<script>

    // properties
    export let branches;
    export let table_templates;

    // import config
    import { ENDPOINT_FILE, ENDPOINT_IMAGE, DEFAULT_SERVER } from '../../../config.js';
    import { IMAGE_STATUS } from '../../../../../meza-imageprocessor/config/config-images.js';

    // reverse IMAGE_STATUS dict
    const IMAGE_STATUS_REVERSE = {};
    for (const key in IMAGE_STATUS) {
        IMAGE_STATUS_REVERSE[IMAGE_STATUS[key]] = key;
    }

    // import lib
    import * as d3 from 'd3';
    import { freeze, unfreeze } from '../../../../../meza-libraries/utils/web/svelte-stores.js';
    import { popup } from '../../../../../meza-libraries/utils/web/prompt.js';
    import { getShortMonthDay } from '../../../../../meza-libraries/gen/datetime.js';
    import { isObject, isStringNonEmpty, isNumber } from '../../../../../meza-libraries/gen/datatype.js';
    import { reqGET, reqPUT } from '../../../../../meza-libraries/http/web/http.js';
    import { loadImage, loadCells, saveCells } from '../libs.js';
    import { set_box_border_color, set_box_cells }  from '../ImageBox/scripts.js';

    // import scripts
    import { run, clear, draw_table_template, computeImageResizeFactor } from './scripts.js';

    // config
    const ID_CANVAS_IMG = 'img-canvas';

    // get session information
    const server = DEFAULT_SERVER;

    // variables
    let loading = false;
    let display = false;
    let ready = false;
    let reprocess = false;

    let image_id;
    let image;
    let cells;
    let table_template;


    function close(){
        display = !display;

        // clear current workspace
        clear();

        // update box border color
        set_box_border_color( image );

        // update box cells 
        set_box_cells( image, table_templates );
        
        // if cells were changed, reprocess image
        if (reprocess) {
            console.log('Info: reprocessing')
            reqPUT(server, ENDPOINT_IMAGE(image_id), { status: IMAGE_STATUS['CUTTING'] });
        }
    }



    async function updateTemplate(_table_template) {

        // check
        if (!isObject(_table_template) || !isNumber(_table_template['id'])) {
            console.error('Invalid table template');
            return;
        }

        // set freeze flag
        freeze();
        const response_image = await reqPUT(server, ENDPOINT_IMAGE(image_id), { 'table_template_id': _table_template['id'] } );
        unfreeze();

        // check
        if (response_image === undefined || response_image === null || !isObject(response_image) || !isNumber(response_image['status']) || response_image['status'] !== 200) {
            console.error('Could not update image');
            return;
        }

        // set flag
        reprocess = true;

        // update image
        table_template = _table_template;
        image['table_template_id'] = _table_template['id'];
        image['status'] = IMAGE_STATUS['CUTTING'];

        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------

        // Get DOM element
        const imgCanvas = document.getElementById(ID_CANVAS_IMG);
        
        // Get the canvas width and height
        const image_width = imgCanvas.width;
        const image_height = imgCanvas.height;

        // compute image position and size in relation to the canvas
        const { resizeFactor, offsetTop, offsetLeft } = computeImageResizeFactor(image_width, image_height);

        // get the circles position from the svg
        const svg = d3.select('#svgbox');
        const circles = svg.selectAll('circle').nodes();
        const corners = circles.map(circle => [(circle.getAttribute('cx') - offsetLeft) / resizeFactor, (circle.getAttribute('cy') - offsetTop) / resizeFactor]);

        // check that we have
        if (corners === undefined || corners === null || !Array.isArray(corners) || corners.length !== 4) {
            console.log('Error: we need 4 corners');
            return;
        }

        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------

        // save
        freeze();
        await saveCells( image_id, table_templates, corners )
        let _;
        const results_cells = await loadCells( image_id, table_templates);
        if (results_cells === null) return;
        [ cells, _ ] = results_cells;
        draw_table_template( table_template, cells, image_id )
        unfreeze();
    }

    async function updateApproved(approved){

        // build payload
        const payload = {
            'approved': approved
        }

        // update image
        freeze();
        const results = await reqPUT(server, ENDPOINT_IMAGE(image_id), payload)
        unfreeze();

        // check if results are valid
        if (!isObject(results)) {
            console.error('Could not update image');
            return;
        }

        // update image
        image['approved'] = approved;
    }



    // function to launch the image box
    export async function show(_image_id, _rect_id = null){

        // set
        image_id = _image_id;
        
        // validate image id
        if (!isStringNonEmpty(image_id)) {
            popup('Invalid image id', 'error')
            return;
        }

        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------

        // get the image info from the server
        freeze();
        const response_image = await reqGET(server, ENDPOINT_IMAGE(image_id));
        unfreeze();
        if (!isObject(response_image)) {
            popup('Invalid image', 'error')
            return;
        }
        image = response_image['data'];

        // set branch name
        const branch = branches.filter(branch => branch['id'] === image['branch_id'])[0];
        if (isObject(branch)) image['branch_name'] = branch['name'];

        // build the link to the image
        const link_to_image = ENDPOINT_FILE(image_id) + '?rotation=' + image['rotation'];

        // load image asset
        freeze();
        const result = await loadImage( link_to_image );
        unfreeze();
        if (result === undefined || result === null) {
            popup('Could not load image', 'error')
            return;
        }
        const asset = result['asset'];
        if (asset === undefined || asset === null) {
            popup('Could not load image', 'error')
            return;
        }

        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------

        // turn on display flag
        display = true;

        // load image cells
        freeze();
        let _;
        const results_cells = await loadCells( image_id, table_templates);
        if (results_cells !== null) {
            [ cells, _ ] = results_cells;
        }

        // wait a bit
        await new Promise(r => setTimeout(r, 150));
        unfreeze();

        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------

        // set table template name
        table_template = table_templates.filter(table_template => table_template['id'] === image['table_template_id'])[0];

        // create callbacks
        const callback_drag = () => { draw_table_template(table_template, cells, image_id); }
        const callback_end = async () => {  updateTemplate(table_template) }

        // draw
        run( image, table_template, cells, asset, callback_drag, callback_end );
   

        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------
        // ------------------------------------------------------------------------------------

        // set ready flag
        ready = true;
    }

</script>

<!-- The Image Box -->
<aside id="image_box" style="display: {display ? "block" : "none"}">
    <button on:click={() => { close(); }} class="lightbutton" id="close" title="Close">
        <img alt="Close" src="/assets/icons/close.svg">
    </button>
    <section>

        {#if ready}
            <div class="left">

                <!-- Title -->
                <h1 style="margin: 0px; margin-bottom: 2px;">{getShortMonthDay(new Date(image.created_at))}</h1>
                <h1 style="margin: 0px; margin-bottom: 24px;">{image['branch_name']}</h1>
                
                
                <h2>Status</h2>
                <h3>{IMAGE_STATUS_REVERSE[image['status']]}</h3>
                <br>

                <h2>Review</h2>
                <h3 id="title-actions">
                    {#if image.approved === undefined || image.approved === null}
                        None
                    {:else if image.approved}
                        Approved
                    {:else if !image.approved}
                        Refused
                    {:else}
                        None
                    {/if}
                </h3>
                <div id="actions-select">
                    <button id="approve" on:click={() => { updateApproved(true) }}>Approve</button>
                    <button id="refuse" on:click={() => { updateApproved(false) }}>Reject</button>
                </div>
                <br>

                {#if image.status > IMAGE_STATUS['CUTTING']}
                <p style="font-style: italic;">Modifications will be saved upon closing of the window.</p>
                {/if}
            </div>
        {/if}

        <div class="right">
            <div id="canvas-container">
                <canvas id="img-canvas"></canvas>
                <canvas id="overlay-canvas"></canvas>
                <canvas id="sketch-canvas"></canvas>                 
                <canvas id="value-canvas"></canvas>
                <svg style="display:none;" id="svgbox"></svg>
            </div>
        </div>
    </section>
</aside>


