<script>

    // import libs
    import { onMount } from 'svelte';
    import { isStringNonEmpty, isEmail, isObject, isNumber, uuidValidateV4 } from '../../../meza-libraries/gen/datatype.js';
    import { reqPOST } from '../../../meza-libraries/http/web/http.js';

    // import config
    import { DEFAULT_SERVER, ENDPOINT_LOGIN_USING_CRED, ENDPOINT_LOGIN_USING_SID } from '../config.js';
    import { freeze, unfreeze } from '../../../meza-libraries/utils/web/svelte-stores.js';
    const server = DEFAULT_SERVER;

    // properties
    export let signed_in;

    // internal variables
    let email;
    let password;
    let p_error_msg = null;


    async function login_with_cred(){

        // reset
        p_error_msg.innerHTML = '';

        // input validation
        if (!isEmail(email)){
            p_error_msg.innerHTML = 'Enter a valid email';
            console.error('Enter a valid email');
            return;
        }
        if (!isStringNonEmpty(password)) {
            p_error_msg.innerHTML = 'Enter a valid email';
            console.error('Enter a valid password');
            return;
        }

        // send
        freeze();
        const response = await reqPOST(server, ENDPOINT_LOGIN_USING_CRED, {
            'email': email,
            'password': password
        });
        unfreeze();

        // check for errors
        if (!isObject(response)){
            p_error_msg.innerHTML = 'http request failed';
            console.error('Error - http request failed');
            return;
        }

        // grab data
        const { status, data } = response;

        if (!isNumber(status) || +status !== 200){
            let message;
            try { message = data.message } catch(err) { message = 'http request failed' };
            p_error_msg.innerHTML = message;
            console.error(`Error - ${message}`);
            return;
        }

        // extract sid
        const sid = response['data']['sid'];

        // check
        if (!uuidValidateV4(sid)){
            p_error_msg.innerHTML = 'invalid sid';
            console.error('Error - invalid sid');
            return;
        }

        // set
        signed_in = true;
    }


    async function login_with_sid() {

        // send
        freeze();
        const response = await reqPOST(server, ENDPOINT_LOGIN_USING_SID, null, 'application/json', null, null, false);
        unfreeze();

        // check for errors
        if (!isObject(response)){
            console.error('Error - http request failed');
            return;
        }

        // grab data
        const { status, data } = response;

        if (!isNumber(status) || +status !== 200){
            let message;
            try { message = data.message } catch(err) { message = 'http request failed' }
            console.error(`Error - ${message}`);
            return;
        }

        // extract access
        const access = isNumber(data['access']) ? data['access'] : null;

        // extract email
        const email = isStringNonEmpty(data['email']) ? data['email'] : null;

        // check
        if (!isNumber(access) || !isStringNonEmpty(email)){
            console.error('Error - invalid access or email');
            return;
        }

        // set
        signed_in = true;
    }


    onMount(async () => {

        // get DOM elements
        p_error_msg = document.getElementById('error-msg');

        // try to login with sid
        await login_with_sid();
    })


</script>


<div class="login-container">
    
    <p>Email</p>
    <input bind:value={email}>

    <p>Password</p>
    <input bind:value={password} type="password">

    <div>
        <button on:click={() => { login_with_cred() }}>Sign In</button>
    </div>

    <p id="error-msg"></p>

</div>


