<script>

    // properties
    let table_templates;

    // import scripts
    import { getTableDimensions, compute_bubbles } from './scripts.js'

    // prompt lib
    import swal from 'sweetalert';

    // ui lib
    import { onMount } from "svelte";

    // import d3
    import * as d3 from 'd3'

    // datatype lib
    import { isNumber, isObject, isString } from '../../../../meza-libraries/gen/datatype.js';
    import { reqGET } from '../../../../meza-libraries/http/web/http.js';

    // import config
    import { DEFAULT_SERVER, ENDPOINT_TABLE_TEMPLATES } from '../../config.js';
    const server = DEFAULT_SERVER;


    // constants
    const borderPadding = 32;
    const offsetY = 32;

    // process var
    let ready = false;
    var rectangles;
    let selected_table_template_name = '';
    let output = '';
    let highlighted_rects_str = '';
    let container;
    let canvasWidth, canvasHeight;

    function gcd (a, b) {
        if(b == 0){
            return a;
        }
        return gcd(b, a%b);
    }

    function gcd_more_than_two_numbers (arr, mul) {
        try {
            return arr.reduce(gcd);
        }catch(err){
            console.error(err);
        }
        return mul;
    }


    function findLayoutGCD(){

        // init all unique values
        let values = new Set();

        // substract from all rect
        rectangles.forEach(rect => {

            // grab all attributes
            const x0 = +rect['x0'];
            const y0 = +rect['y0'];
            const w = +rect['w'];
            const h = +rect['h'];

            // add values
            values.add(w);
            values.add(h);
            values.add(x0);
            values.add(y0);
        })

        // convert to array
        values = [...values];

        // multiply by a large number that will make sure everything is an integer
        const multiplier = 1000000;
        values = values.map(v => v * multiplier);

        // find GCD
        const GCD = multiplier / gcd_more_than_two_numbers(values, multiplier);

        return GCD;
    }


    function compute(){

        // remove x, y offset
        let x_offset = Infinity;
        let y_offset = Infinity;

        // find offset
        rectangles.forEach(rect => {
            const { x0, y0 } = rect;
            if ( x0 < x_offset ) x_offset = x0;
            if ( y0 < y_offset ) y_offset = y0;
        })

        // remove offset
        rectangles.forEach(rect => {

            // grab data
            const x0 = +rect['x0'];
            const y0 = +rect['y0'];

            // update
            rect['x0'] = x0 - x_offset;
            rect['y0'] = y0 - y_offset;
        })

        // find the GCD
        const GCD = findLayoutGCD();

        // divide by the GCD
        rectangles.forEach(rect => {

            // grab all attributes
            const x0 = +rect['x0'];
            const y0 = +rect['y0'];
            const w = +rect['w'];
            const h = +rect['h'];

            // update
            rect['x0'] = Math.round(x0 * GCD);
            rect['y0'] = Math.round(y0 * GCD);
            rect['w'] = Math.round(w * GCD);
            rect['h'] = Math.round(h * GCD);
        })

        // display
        output = JSON.stringify(rectangles);
    }


    function updateTableTemplate(table_template){

        // get ui elements
        container = document.getElementById('canvas-container');

        // Get dimensions
        canvasWidth = container.clientWidth;
        canvasHeight = container.clientHeight;

        // reset output
        output = '';

        // set name
        selected_table_template_name = table_template['name']

        // grab rectangles
        rectangles = table_template['rectangles'];

        // get table size
        let { width, height } = getTableDimensions(rectangles);

        // get scaling factor between actual and displayed table
        const factor = Math.min(...[(canvasWidth - 2*borderPadding) / width, (canvasHeight - 2*borderPadding) / height]);

        // new dimensions
        const newWidth = factor * width;
        const newHeight = factor * height;

        // compute offsets
        const offsetX = Math.floor((canvasWidth - newWidth) / 2.0);

        // compute font size
        let font_size = width;
        rectangles.forEach(rectangle => {

            // grab info
            const { data_type, opts, w, h } = rectangle;

            // use height
            const _h = Math.ceil(0.8 * (+h));
            if ( _h < font_size ) font_size = _h;

            // grab text
            const text = data_type === 'info' ? opts : data_type;
            if (!isString(text) || text.length === 0) return;

            // use text
            const _font_size = Math.ceil( w / (text.length + 0.0000001) );
            if (_font_size < font_size) font_size = _font_size;

        });

        // create svg
        const svg = d3.select('#canvas')
                        .attr('width', canvasWidth)
                        .attr('height', canvasHeight)

        // clear
        svg.selectAll('*').remove();

        // create group in which we will append our objects
        const text_g = svg.append('g')
        const rectid_g = svg.append('g')
        const label_g = svg.append('g')
        // const bubble_g = svg.append('g')
        const rect_g = svg.append('g')

        // scale
        rect_g.attr('transform', `translate(${offsetX}, ${offsetY}), scale(${factor})`)
        // bubble_g.attr('transform', `translate(${offsetX}, ${offsetY}), scale(${factor})`)
        rectid_g.attr('transform', `translate(${offsetX}, ${offsetY}), scale(${factor})`)
        label_g.attr('transform', `translate(${offsetX}, ${offsetY}), scale(${factor})`)
        text_g.attr('transform', `translate(${offsetX}, ${offsetY}), scale(${factor})`)


        // draw text
        text_g.selectAll('text')
            .data(rectangles) //.filter(r => r['data_type'] !== 'bubble')
            .enter()
            .append('text')
            .attr('text-anchor', 'middle')
            .attr('font-family', 'sans-serif')
            .attr('x', d => d.x0 + d.w/2.0)
            .attr('y', d => d.y0 + 2.0*d.h/3.0)
            .attr("font-size", `${font_size}px`)
            .text(d => d['data_type'] === 'info' ? d['opts'] : d['data_type'])


        // draw rect ids
        rectid_g.selectAll('text')
            .data(rectangles) //.filter(r => r['data_type'] !== 'bubble')
            .enter()
            .append('text')
            .attr('text-anchor', 'start')
            .attr('font-family', 'sans-serif')
            .attr('x', d => d.x0 + Math.ceil(font_size/2.0))
            .attr('y', d => d.y0 + font_size + 2)
            .attr("font-size", `${Math.ceil(font_size)}px`)
            .text(d => {
                return d['id']
            })


        // draw label
        label_g.selectAll('text')
            .data(rectangles) //.filter(r => r['data_type'] !== 'bubble')
            .enter()
            .append('text')
            .attr('text-anchor', 'start')
            .attr('font-family', 'sans-serif')
            .attr('x', d => d.x0 + Math.ceil(font_size/2.0))
            .attr('y', d => d.y0 + font_size + 2 + font_size + 2)
            .attr("font-size", `${Math.ceil(font_size)}px`)
            .text(d => {
                return d['label'] === undefined ? '' : d['label'];
            })

        // store selected rect ids
        let rect_ids = new Set();

        // draw rectangles
        rect_g.selectAll('rect')
            .data(rectangles)
            .enter()
            .append('rect')
            .attr('x', d => d.x0)
            .attr('y', d => d.y0)
            .attr('width', d => d.w)
            .attr('height', d => d.h)
            .attr('fill', '#fff')
            .attr('stroke', '#000')
            .attr('stroke-width', '3px')
            .attr('opacity', 0.7)
            .on('mouseover', function(){
                d3.select(this).attr('opacity', 0.2)
            })
            .on('mouseout', function(){
                if (mouseDown) return;
                rect_g.selectAll('rect').attr('opacity', 0.7)
            })
            .on('mousemove', (e, d) => {
                if (!mouseDown) return;
                rect_ids.add(d['id'])
                highlighted_rects_str = [...rect_ids].join(', ');
            })
            .on('mouseup', (e, d) => {

                // init
                let _rect_ids = [];

                // selected rectangles as an array
                if (rect_ids.size > 0){
                    _rect_ids = [...rect_ids]
                    rect_ids.clear();
                }else{
                    _rect_ids = [d['id']]
                }

                // displayed info about the rectangle
                let rect_info = '';
                if(_rect_ids.length === 1){
                    rect_info = `${d.data_type}`
                    if (d.opts !== undefined && d.opts.length > 0){
                        rect_info = `${rect_info}\n${d.opts}`
                    }
                }

                let rect_label = '';
                if(_rect_ids.length === 1){
                    rect_label = `${d.label}`
                }


                // check if shift key was pressed during click
                const shift_pressed = e['shiftKey'];

                if (!shift_pressed) {

                    swal({
                        title: 'Edit Data Type',
                        text: rect_info,
                        content: {
                            element: "input",
                            attributes: {
                                placeholder: "Type a datatype or opts"
                            },
                        },
                        buttons: {
                            cancel: "Cancel",
                            confirm: "Confirm"
                        }
                    })
                    .then(input => {
                        if (input === undefined || input === null || typeof(input) !== 'string') return;
                        const _text_g = text_g.selectAll('text').filter(t => _rect_ids.includes(t['id']))
                        input = input.trim();

                        rectangles.forEach(r => {
                            if (!_rect_ids.includes(r['id'])) return;
                            if (['info', 'string', 'blackout', 'bubble', 'float', 'integer'].includes(input)){
                                r['data_type'] = input
                                r['opts'] = ''
                                _text_g.text(input)
                            }else if(input.includes(',')){
                                r['data_type'] = 'bubble'
                                r['opts'] = input
                                _text_g.text('bubble')
                            }else{
                                r['data_type'] = 'info'
                                r['opts'] = input
                                _text_g.text('info')
                            }
                        })
                    })

                } else {

                    swal({
                        title: 'Edit Label',
                        text: rect_label,
                        content: {
                            element: "input",
                            attributes: {
                                placeholder: "Type the label"
                            },
                        },
                        buttons: {
                            cancel: "Cancel",
                            confirm: "Confirm"
                        }
                    })
                    .then(input => {
                        
                        // validate
                        if (input === undefined || input === null || typeof(input) !== 'string') return;
                        input = input.trim();

                        // set input
                        rectangles.forEach(r => {
                            if (!_rect_ids.includes(r['id'])) return;

                            // set label
                            r['label'] = input;

                            // add to label_g
                            const _label_g = label_g.selectAll('text').filter(t => _rect_ids.includes(t['id']));

                            // update label
                            _label_g.text(input)
                        })
                    })
                }
            })


        // mouse down detector
        var mouseDown = 0;
        document.body.onmousedown = function() {
            ++mouseDown;
        }
        document.body.onmouseup = function() {
            --mouseDown;
        }
    }


    onMount(async () => {

        // load table templates
        const results = await reqGET(server, ENDPOINT_TABLE_TEMPLATES)

        // check results
        if (results === undefined || results === null) {
            console.error('Failed to load table templates')
            return;
        }

        // grab from results
        table_templates = results['data'];

        // update page template
        if (Array.isArray(table_templates) && table_templates.length > 0){
            updateTableTemplate(table_templates[0])
        }

        // set flag
        ready = true;
    })

</script>


<!-- Side Panel -->
<aside id="side-panel">

    <h3 style="padding-top: 0px;">
        Logbooks
    </h3>
    <p style="margin: 0px; padding: 0px; margin-bottom: 4px;">{selected_table_template_name}</p>
    <div id="template-select" class="vertical-menu">
        {#if ready}
        {#each table_templates as table_template}
            <!-- svelte-ignore a11y-click-events-have-key-events -->
            <p on:click={() => { updateTableTemplate(table_template) }} class="vertical-menu-entry">
                {table_template['id']}: {table_template['name']}
            </p>
        {/each}
        {/if}
    </div>

    <br><br>
    <h3 style="padding-top: 0px;">
        Compute
    </h3>
    <textarea rows="4" style="overflow-y: scroll;">{output}</textarea>
    <br>
    <button on:click={() => { compute(); }}>
        Run
    </button>

    <!-- Highlighted Rects -->
    <br><br>
    {#if highlighted_rects_str.length > 0}
        <h3 style="padding-top: 0px;">
            Highlighted Rectangles IDs:
        </h3>
        <textarea rows="4" style="overflow-y: scroll;">{highlighted_rects_str}</textarea>
    {/if}

</aside>


<div id="canvas-container">
    <!-- Canvas -->
    <svg id="canvas"></svg>
</div>


