export async function loadImage( endpoint ) {

    // Fetch the image
    let response = await fetch(endpoint);
    let imageDataHeader = response.headers.get('x-image-metadata');

    // Create a blob
    let blob = await response.blob();
    
    // Create object URL
    let imageURL = URL.createObjectURL(blob);

    // send a request for the image
    let asset = null;
    let success = false;
    await new Promise(function (resolve, reject) {
        asset = new Image()
        asset.onload = () => {
            success = true;
            resolve();
        }
        asset.onerror = () => {
            resolve();
        }
        asset.src = imageURL
    })
    
    // validate
    if (!success) return null;

    // if we have a header, parse it
    if (isStringNonEmpty(imageDataHeader)) {
        const imageData = JSON.parse(imageDataHeader);
        return {
            asset: asset,
            ...imageData
        }
    } else {
        return {
            asset: asset
        }
    }
}

export function getCornerPoints(rectangles, cells) {
    
    // Push the 4 corners of each rectangles to points
    let points = [];
    rectangles.forEach(r => {
        // unpack
        const { id, x0, y0, w, h } = r;
        // push points
        points.push([ id, x0, y0 ]);         // top-left corner
        points.push([ id, x0 + w, y0 ]);     // top-right corner
        points.push([ id, x0 + w, y0 + h ]); // bottom-right corner
        points.push([ id, x0, y0 + h ]);     // bottom-left corner
    })

    // Get the center of all points
    let sumX = 0;
    let sumY = 0;
    let numPoints = points.length;
    points.forEach(point => {
        sumX += point[1];
        sumY += point[2];
    });
    const cx = sumX / numPoints;
    const cy = sumY / numPoints;

    // initialize the corners
    let tl = { id: null, x: Infinity, y: Infinity };
    let tr = { id: null, x: -Infinity, y: Infinity };
    let br = { id: null, x: -Infinity, y: -Infinity };
    let bl = { id: null, x: Infinity, y: -Infinity };
    
    // Define the initial distance for each corner as negative infinity
    let minDistTL = -Infinity;
    let minDistTR = -Infinity;
    let minDistBR = -Infinity;
    let minDistBL = -Infinity;

    // Iterate over points
    points.forEach(point => {
        // unpack
        const [ id, x, y ] = point;

        // calculate distance from center
        const dist = Math.sqrt( Math.pow(cx - x, 2) + Math.pow(cy - y, 2) )

        // check in which quadrant the point is and if it's closer to the center than the previous point in this quadrant
        if (x < cx && y < cy && dist > minDistTL) { // Top-left quadrant
            tl = { id, x, y };
            minDistTL = dist;
        } else if (x > cx && y < cy && dist > minDistTR) { // Top-right quadrant
            tr = { id, x, y };
            minDistTR = dist;
        } else if (x > cx && y > cy && dist > minDistBR) { // Bottom-right quadrant
            br = { id, x, y };
            minDistBR = dist;
        } else if (x < cx && y > cy && dist > minDistBL) { // Bottom-left quadrant
            bl = { id, x, y };
            minDistBL = dist;
        }
    });

    // get the corresponding cells
    const cell_tl = cells.filter(cell => +cell['rect_id'] === +tl.id)[0];
    const cell_tr = cells.filter(cell => +cell['rect_id'] === +tr.id)[0];
    const cell_br = cells.filter(cell => +cell['rect_id'] === +br.id)[0];
    const cell_bl = cells.filter(cell => +cell['rect_id'] === +bl.id)[0];

    // get corners
    tl = { x: cell_tl['tl_x'], y: cell_tl['tl_y'] };
    tr = { x: cell_tr['tr_x'], y: cell_tr['tr_y'] };
    br = { x: cell_br['br_x'], y: cell_br['br_y'] };
    bl = { x: cell_bl['bl_x'], y: cell_bl['bl_y'] };

    // Corners
    return [[tl.x, tl.y], [tr.x, tr.y], [br.x, br.y], [bl.x, bl.y]];
}


export function reproject(src_points, dst_points, rectangles) {

    // projection matrix
    const srcPoints = new cv.Mat(4, 1, cv.CV_32FC2);
    srcPoints.data32F.set(src_points);
    const dstPoints = new cv.Mat(4, 1, cv.CV_32FC2);
    dstPoints.data32F.set(dst_points);
    const homographyMatrix = cv.findHomography(srcPoints, dstPoints, cv.RANSAC);

    // project the points
    const rectangles_projected = rectangles.map(rectangle => {

        // extract
        const { tl_x, tl_y, tr_x, tr_y, br_x, br_y, bl_x, bl_y } = rectangle;

        // convert to array
        const points = [tl_x, tl_y, tr_x, tr_y, br_x, br_y, bl_x, bl_y];

        // create a mat for the rectangle's corners
        const rectCorners = new cv.Mat(4, 1, cv.CV_32FC2);
        rectCorners.data32F.set(points);

        // reproject
        const transformedCorners = new cv.Mat();
        cv.perspectiveTransform(rectCorners, transformedCorners, homographyMatrix);

        // transformedCorners now contains the reprojected corners of the rectangle
        // Note that these are not necessarily axis-aligned anymore.
        const transformedCornersData = transformedCorners.data32F;

        // release
        rectCorners.delete();
        transformedCorners.delete();

        return {
            tl_x: 1.0 * transformedCornersData[0],
            tl_y: 1.0 * transformedCornersData[1],
            tr_x: 1.0 * transformedCornersData[2],
            tr_y: 1.0 * transformedCornersData[3],
            br_x: 1.0 * transformedCornersData[4],
            br_y: 1.0 * transformedCornersData[5],
            bl_x: 1.0 * transformedCornersData[6],
            bl_y: 1.0 * transformedCornersData[7]
        }        
    });

    // release
    srcPoints.delete();
    dstPoints.delete();
    homographyMatrix.delete();

    // return
    return rectangles_projected;
}


function project_table_template(rectangles, dst_points) {

    // get the width and height of the table template
    const width = Math.max(...rectangles.map(rectangle => rectangle.w + rectangle.x0));
    const height = Math.max(...rectangles.map(rectangle => rectangle.h + rectangle.y0));

    // projection matrix
    const src_points = [0, 0, width, 0, width, height, 0, height];

    // points
    const points = rectangles.map(rectangle => {

        // init
        let x, y, w, h;
        x = rectangle.x0;
        y = rectangle.y0;
        w = rectangle.w;
        h = rectangle.h;

        return {
            tl_x: x,
            tl_y: y,
            tr_x: x + w,
            tr_y: y,
            br_x: x + w,
            br_y: y + h,
            bl_x: x,
            bl_y: y + h
        }
    });

    // project
    const rectangles_projected = reproject(src_points, dst_points, points);

    // set other attributes
    rectangles_projected.forEach((rectangle, i) => {

        // other
        const rect_id = rectangles[i].id;
        const data_type = rectangles[i].data_type;
        const opts = rectangles[i].opts;

        // set
        rectangle.rect_id = rect_id;
        rectangle.data_type = data_type;
        rectangle.opts = opts;

        // remove value
        delete rectangle.value;
    });

    return rectangles_projected;
}


export async function saveCells( image_id, table_templates, corners ) {

    // get image info
    const response_image = await reqGET(server, ENDPOINT_IMAGE(image_id));

    // check
    if (response_image === undefined || response_image === null || !isObject(response_image) || !isNumber(response_image['status']) || response_image['status'] !== 200) return null;
        
    // unpack
    const image = response_image['data'];
    const table_template_id = image['table_template_id'];

    // --------------------------------------------------------------------------------------------------------------

    // if no table template id, return empty
    if ( !isNumber(table_template_id) ){
        return null;
    }

    // get table template
    const table_template = table_templates.filter(tt => +tt['id'] === +table_template_id)[0];

    // if no table template, return empty
    if ( !isObject(table_template) || !isArrayNonEmpty(table_template.rectangles) ){
        return null;
    }

    // --------------------------------------------------------------------------------------------------------------

    // reproject
    const corners_flat = corners.map(corner => [corner[0], corner[1]]).flat();
    const rectangles = project_table_template(table_template.rectangles, corners_flat);

    const response_cells = await reqPOST(server, ENDPOINT_CELL(image_id), { rectangles: rectangles });

    // check
    if (response_cells === undefined || response_cells === null || !isObject(response_cells) || !isNumber(response_cells['status']) || response_cells['status'] !== 200) return null;
}


export async function loadCells( image_id, table_templates ) {

    // get image info
    const response_image = await reqGET(server, ENDPOINT_IMAGE(image_id));
    
    // check
    if (response_image === undefined || response_image === null || !isObject(response_image) || !isNumber(response_image['status']) || response_image['status'] !== 200) return null;
        
    // unpack
    const image = response_image['data'];
    const table_template_id = image['table_template_id'];

    // --------------------------------------------------------------------------------------------------------------
    
    // if no table template id, return empty
    if ( !isNumber(table_template_id) ){
        return null;
    }

    // get table template
    const table_template = table_templates.filter(tt => +tt['id'] === +table_template_id)[0];

    // if no table template, return empty
    if ( !isObject(table_template) || !isArrayNonEmpty(table_template.rectangles) ){
        return null;
    }

    // --------------------------------------------------------------------------------------------------------------

    // get image width and height
    const response_cells = await reqGET(server, ENDPOINT_CELL(image['id']));
    const response_metadata = await reqGET(server, ENDPOINT_FILE_METADATA(image['id']));
    
    // check
    if (response_cells === undefined || response_cells === null || !isObject(response_cells) || !isNumber(response_cells['status']) || response_cells['status'] !== 200) return null;
    if (response_metadata === undefined || response_metadata === null || !isObject(response_metadata) || !isNumber(response_metadata['status']) || response_metadata['status'] !== 200) return null;

    // unpack
    const cells = response_cells['data'];
    const metadata = response_metadata['data'];
    const width_image = metadata['width'];
    const height_image = metadata['height'];

    // get the width and height of the table template
    const width_template = Math.max(...table_template.rectangles.map(rectangle => rectangle.w + rectangle.x0));
    const height_template = Math.max(...table_template.rectangles.map(rectangle => rectangle.h + rectangle.y0));

    // --------------------------------------------------------------------------------------------------------------

    if ( !isArrayNonEmpty(cells) ) {

        // resize the table template to fit the width and height of the image
        const resizeFactor = 0.8 * Math.min(width_image / width_template, height_image / height_template);
        const offsetLeft = (width_image - width_template * resizeFactor) / 2;
        const offsetTop = (height_image - height_template * resizeFactor) / 2;
        const rectangles = table_template.rectangles.map(rectangle => {

            // extract
            const { x0, y0, w, h, data_type, opts, id } = rectangle;
            const rect_id = id;
            const value = null;

            // compute
            const x0_new = x0 * resizeFactor + offsetLeft;
            const y0_new = y0 * resizeFactor + offsetTop;
            const w_new = w * resizeFactor;
            const h_new = h * resizeFactor;

            // convert to tl, tr, br, bl
            const tl_x = x0_new;
            const tl_y = y0_new;
            const tr_x = x0_new + w_new;
            const tr_y = y0_new;
            const br_x = x0_new + w_new;
            const br_y = y0_new + h_new;
            const bl_x = x0_new;
            const bl_y = y0_new + h_new;
            
            // return
            return { tl_x, tl_y, tr_x, tr_y, br_x, br_y, bl_x, bl_y, data_type, opts, rect_id, value };
        })

        return [rectangles, table_template];
    }

    // --------------------------------------------------------

    // map cell values, by id 
    const cells_value_map = {};
    cells.forEach(cell => {
        cells_value_map[cell['rect_id']] = cell['value']
    });
    
    // find the corner points of the cells
    const corners = getCornerPoints(table_template.rectangles, cells);
    const corners_flat = corners.map(corner => [corner[0], corner[1]]).flat();

    // reproject
    const rectangles = project_table_template(table_template.rectangles, corners_flat);

    // set the value of the cells
    rectangles.forEach(rectangle => {
        rectangle.value = cells_value_map[rectangle.rect_id];
    });

    return [rectangles, table_template];
}
