export function getTableDimensions(rectangles){

    // Count
    let templateWidth = 0.0
    let templateHeight = 0.0

    // Create an array with all the cell info
    rectangles.forEach(rect => {
        // Dimensions
        const { x0, y0, w, h } = rect;

        // Get the max
        if (x0 + w > templateWidth) {
            templateWidth = x0 + w
        }
        if (y0 + h > templateHeight) {
            templateHeight = y0 + h
        }
    })

    return {
        'width': templateWidth,
        'height': templateHeight
    }
}


export function compute_bubbles(rectangle){

    // get data
    const { x0, y0, w, h, opts } = rectangle;

    // parse options
    const _opts = opts.split(',')
    const nbrOfOpts = _opts.length

    const bubbleMaxWidth = w / (1.0 * nbrOfOpts)
    const bubbleMaxHeight = h
    let bubbleRadius = Math.min(...[bubbleMaxWidth, bubbleMaxHeight]) / 2.0
    bubbleRadius = bubbleRadius - cellPadding
    if (bubbleRadius <= 0) {
        bubbleRadius = 1;
    }

    const emptySpace = w - (2 * bubbleRadius * nbrOfOpts)
    const bubblePadding = emptySpace / (2.0 * nbrOfOpts)

    let bubbles = []
    for (let j = 0; j < nbrOfOpts; j++) {
        const cX = x0 + (bubblePadding + bubbleRadius) * (2 * j + 1)
        const cY = y0 + h / 2.0
        bubbles.push([cX, cY, bubbleRadius])
    }

    return bubbles;
}
