<script>

    // import libs
    import { onMount } from 'svelte';
    import { reqGET } from '../../../../meza-libraries/http/web/http.js';
    import { isNumber, isObject, isArray, uuidValidateV4 } from '../../../../meza-libraries/gen/datatype.js';
    import { getUrlParams } from '../../../../meza-libraries/http/web/url.js';
    import { getFormattedDateTime } from '../../../../meza-libraries/gen/datetime.js';

    // import config
    import { DEFAULT_SERVER, ENDPOINT_IMAGES_STATISTICS, ENDPOINT_BRANCHES, ENDPOINT_IMAGES, ENDPOINT_TABLE_TEMPLATES, ENDPOINT_PROJECT, ENDPOINT_EXPORT } from '../../config.js';
    const server = DEFAULT_SERVER;

    // import components
    import ImageEditor from './ImageEditor/ImageEditor.svelte';
    import ImageBox from './ImageBox/ImageBox.svelte';
    import { freeze, unfreeze } from '../../../../meza-libraries/utils/web/svelte-stores.js';

    // the project data from the meza server
    let ready = false, ready_2 = false;
    let openImageBox;
    let project, branches, table_templates, statistics;
    let images = [];

    // filters
    let branchIdFilter = null;


    // grab params from url
    const { image_id, rect_id } = getUrlParams(window.location.href);
    

    async function getData() {

        // request from server
        let promises = []
        promises.push(reqGET(server, ENDPOINT_PROJECT))
        promises.push(reqGET(server, ENDPOINT_BRANCHES))
        promises.push(reqGET(server, ENDPOINT_IMAGES))
        promises.push(reqGET(server, ENDPOINT_TABLE_TEMPLATES))
        promises.push(reqGET(server, ENDPOINT_IMAGES_STATISTICS))

        // request data from server
        const responses = await Promise.all(promises).catch(error => {
            console.error(error)
            return null;
        });

        // check
        if (!isArray(responses) || responses.length !== promises.length){
            console.error(`Could not load the data.`, 'error');
            return null;
        }

        // check
        if (responses.filter(r => !isObject(r)).length > 0 ||
            responses.filter(r => !isNumber(r['status'])).length > 0){
            console.error(`Could not load the data.`, 'error');
            return null;
        }

        // extract status
        const statuses = responses.map(r => +r['status']);
        
        // need to refresh sid
        if (statuses.includes(401)){
            console.error(`Could not load the data.`, 'error')
            window.location.reload();
            return null;
        }

        // failed
        if (statuses.filter(s => s >= 400).length > 0){
            console.error(`Could not load the data.`, 'error');
            return null;
        }

        // unpack
        return responses.map(r => r['data']);
    }

    
    onMount(async () => {

        // init data loader cron job
        freeze();
        const data = await getData();    
        unfreeze();
        
        // check
        if (data === undefined || data === null || !isArray(data)){
            console.error(`Could not load the data.`, 'error');
            return null;
        }

        // unpack
        [ project, branches, images, table_templates, statistics ] = data;

        // convert branches to mapping of id to name
        const branch_id_to_name = branches.reduce((acc, branch) => {
            acc[branch['id']] = branch['name'];
            return acc;
        }, {});

        // set branch name for each image
        images.forEach(image => {
            image['branch_name'] = image['branch_id'] === null ? 'Unknown' : branch_id_to_name[image['branch_id']];
        });

        // sort images in descending chronological
        images.sort((a, b) => new Date(b['created_at']) - new Date(a['created_at']));

        // combine images and statistics
        images = images.map(image => {
            const image_statistics = statistics.find(s => s['image_id'] === image['id']);
            return {
                ...image,
                ...image_statistics
            }
        });

        // filter images by 'created_at' less than 3 months
        const date_now = new Date();
        const three_months_ago = new Date(date_now.getFullYear(), date_now.getMonth() - 3, 1);
        images = images.filter(image => new Date(image['created_at']) >= three_months_ago);

        // log number of images displayed
        console.log(`Displaying ${images.length} images, since ${three_months_ago.toDateString()}`);
        
        // set freeze flag
        freeze();

        // set ready flags
        ready = true;

        // wait
        await new Promise(r => setTimeout(r, 300));

        // set ready flags
        ready_2 = true;

        // wait
        await new Promise(r => setTimeout(r, 300));

        // set freeze flag
        unfreeze();

        // if image_id is valid, open image box
        if (uuidValidateV4(image_id)){

            // clear params in url bar
            window.history.replaceState(null, null, window.location.pathname);

            // open image to this
            openImageBox(image_id, rect_id);
        }
    });

    /**
    * This function prompts the user with a downloadable file containing all the cells of the images in the news feed
    */
    export const downloadData = async function() {

        // set freeze flag
        freeze();

        // send post request
        const results = await reqGET(server, ENDPOINT_EXPORT);

        // set freeze flag
        unfreeze();

        // validate
        if (!isObject(results)) {
            console.error('failed to retrieve data', 'error');
            return;
        }

        // check
        const { status, data } = results;
        if (!isNumber(status) || +status >= 400) {
            console.error('failed to retrieve data', 'error');
            return;
        }

        // convert to CSV string
        const csv = data.map(row => `"${row.join('","')}"`).join('\n');

        // Create the filename
        const filename = 'meza_' + getFormattedDateTime(0) + '.csv'
        const blob = new Blob([csv], { type: 'text/csv' })

        // Prompt the user to download
        if (window.navigator.msSaveOrOpenBlob) {
            window.navigator.msSaveBlob(blob, filename)
        } else {
            const elem = window.document.createElement('a')
            elem.href = window.URL.createObjectURL(blob)
            elem.download = filename
            document.body.appendChild(elem)
            elem.click()
            document.body.removeChild(elem)
        }
    }

</script>


{#if ready}
    {#if ready_2}

    <div id="labels-container">
        <p style="color: #aaa">
            Being Processed
        </p>
        <p style="color: #0b75c1">
            Approved
        </p>
        <p style="color: #f00">
            Rejected
        </p>
        <p style="color: #ff9900">
            Review
        </p>
    </div>


    <!-- Select Branch ID -->
    <select id="filter-branch" bind:value={branchIdFilter}>
        <option value={null}>All Branches</option>
        {#each branches as branch}
            <option value={branch.id}>{branch.name}</option>
        {/each}
    </select>


    <div id="imageGallery">
        {#each images as image}
            <ImageBox image={image} table_templates={table_templates} bind:branchIdFilter={branchIdFilter} bind:openImageBox={openImageBox}/>
        {/each}
    </div>

    <button id="download-button" on:click={() => { downloadData(); }} >
        <!-- img -->
        <img alt="download" src="./assets/icons/download.png" width="60px" height="60px">
    </button>

    {/if}
    
    <ImageEditor bind:show={openImageBox} branches={branches} table_templates={table_templates}/>
{/if}


