'use strict';

// import config
import { DEFAULT_SERVER, THUMBNAIL_WIDTH } from '../../../config.js';
const server = DEFAULT_SERVER;

// import libs
import { loadImage, loadCells, getCornerPoints } from '../libs.js';
import { IMAGE_STATUS } from '../../../../../meza-imageprocessor/config/config-images.js';


const COLOR_REJECTED = '#ff0000';
const COLOR_APPROVED = '#0b75c1';
const COLOR_REVIEW = '#ff9900';
const COLOR_BEING_PROCESSED = '#aaa';


export function set_box_border_color( image ){

    // unpack
    const image_id = image['id'];
    const approved = image['approved'] === true;
    const rejected = image['approved'] === false;
    const status = image['status'];

    // get the imageGallery
    const imageGallery = document.getElementById('imageGallery');

    // inside the imageGallery, the imageContainer that has a data-image_id attribute equal to the image id
    const imageContainer = imageGallery.querySelector('[data-image_id="' + image_id + '"]');

    // set border color
    if (approved) {
        imageContainer.style.borderColor = COLOR_APPROVED;
    } else if (rejected) {
        imageContainer.style.borderColor = COLOR_REJECTED;
    } else if (status === IMAGE_STATUS['ANNOTATION'] || status === IMAGE_STATUS['DONE']){
        imageContainer.style.borderColor = COLOR_REVIEW;
    } else {
        imageContainer.style.borderColor = COLOR_BEING_PROCESSED;
    }
}


export async function set_box_thumbnail( image, table_templates ){

    // unpack
    const image_id = image['id'];

    // create link to thumbnail
    const thumbnail = server + '/api/files/' + image_id + '?resize=' + THUMBNAIL_WIDTH + '&rotation=' + image['rotation'];
    
    // get the imageGallery
    const imageGallery = document.getElementById('imageGallery');

    // inside the imageGallery, the imageContainer that has a data-image_id attribute equal to the image id
    const imageContainer = imageGallery.querySelector('[data-image_id="' + image_id + '"]');

    // inside the imageContainer, get the canvas with the class name canvas-cells
    const canvas_image = imageContainer.querySelector('.canvas-image');
    const canvas_cells = imageContainer.querySelector('.canvas-cells');
    
    // load image
    const results = await loadImage( thumbnail );

    // check
    if (results === null) return;

    // unpack
    const { asset, ratio } = results;
    
    // get dimensions
    const image_width = asset.width;
    const image_height = asset.height;

    // Set canvas style dimensions
    canvas_image.width = image_width;
    canvas_image.height = image_height;
    canvas_cells.width = image_width;
    canvas_cells.height = image_height;

    // set attributes on canvas 
    imageContainer.setAttribute('data-ratio', ratio);

    // get context
    const ctx_image = canvas_image.getContext('2d');
    const ctx_cells = canvas_cells.getContext('2d');

    // clear
    ctx_image.clearRect(0, 0, image_width, image_height);
    ctx_cells.clearRect(0, 0, image_width, image_height);

    // draw image
    ctx_image.drawImage(asset, 0, 0, image_width, image_height);

    // set
    await set_box_cells( image, table_templates, ratio );
}


export async function set_box_cells( image, table_templates, ratio = null ){ 

    // unpack
    const image_id = image['id'];
    const rejected = image['approved'] === false;

    // get the imageGallery
    const imageGallery = document.getElementById('imageGallery');

    // inside the imageGallery, the imageContainer that has a data-image_id attribute equal to the image id
    const imageContainer = imageGallery.querySelector('[data-image_id="' + image_id + '"]');

    // inside the imageContainer, get the canvas with the class name canvas-cells
    const canvas_cells = imageContainer.querySelector('.canvas-cells');
    
    // get context
    const ctx_cells = canvas_cells.getContext('2d');

    // clear
    ctx_cells.clearRect(0, 0, canvas_cells.width, canvas_cells.height);

    // check
    if (rejected) return;

    // ------------------------------------------------------------------------------------
    // ------------------------------------------------------------------------------------
    // ------------------------------------------------------------------------------------

    // get ratio
    if (ratio === null) {
        const dataset = Object.assign({}, imageContainer.dataset);
        ratio = parseFloat(dataset['ratio']);
    }
    if (ratio === null || ratio === undefined || isNaN(ratio)) return;

    // load content
    const results_cells = await loadCells( image_id, table_templates);
    if (results_cells === null) return;
    const [ cells, table_template ] = results_cells;

    // check
    if (cells === null || !Array.isArray(cells)) return;

    // draw cells
    cells.forEach(cell => {
        ctx_cells.beginPath();
        ctx_cells.strokeStyle = COLOR_APPROVED;
        ctx_cells.lineWidth = 0.5;
        ctx_cells.moveTo(cell['tl_x'] * ratio, cell['tl_y'] * ratio);
        ctx_cells.lineTo(cell['tr_x'] * ratio, cell['tr_y'] * ratio);
        ctx_cells.lineTo(cell['br_x'] * ratio, cell['br_y'] * ratio);
        ctx_cells.lineTo(cell['bl_x'] * ratio, cell['bl_y'] * ratio);
        ctx_cells.closePath();
        ctx_cells.stroke();
    });

    // get corners
    const corners = getCornerPoints(table_template.rectangles, cells);
    const tl_x = corners[0][0];
    const tl_y = corners[0][1];
    const tr_x = corners[1][0];
    const tr_y = corners[1][1];
    const br_x = corners[2][0];
    const br_y = corners[2][1];
    const bl_x = corners[3][0];
    const bl_y = corners[3][1];

    // set corners on DOM element
    imageContainer.setAttribute('data-tl_x', tl_x);
    imageContainer.setAttribute('data-tl_y', tl_y);
    imageContainer.setAttribute('data-tr_x', tr_x);
    imageContainer.setAttribute('data-tr_y', tr_y);
    imageContainer.setAttribute('data-br_x', br_x);
    imageContainer.setAttribute('data-br_y', br_y);
    imageContainer.setAttribute('data-bl_x', bl_x);
    imageContainer.setAttribute('data-bl_y', bl_y);

    // draw corners as circles
    corners.forEach(corner => {
        
        // unpack
        const [ x, y ] = corner;

        // draw
        ctx_cells.beginPath();
        ctx_cells.arc(x * ratio, y * ratio, 0, 0, 2 * Math.PI);
        ctx_cells.fillStyle = COLOR_APPROVED;
        ctx_cells.fill();
        ctx_cells.closePath();
    });    
}


function rotate90(width, corners) {
    let newCorners = [];
    
    for (let i = 0; i < corners.length; i++) {
        let [x, y] = corners[i];
        newCorners.push([y, width - x]);
    }

    // Adjust the order of the corners.
    newCorners = [
        newCorners[1], // new top-left
        newCorners[2], // new top-right
        newCorners[3], // new bottom-right
        newCorners[0]  // new bottom-left
    ];
    
    return newCorners;
}


export function get_rotated_corners( image ) {

    // unpack
    const image_id = image['id'];

    // get the imageGallery
    const imageGallery = document.getElementById('imageGallery');

    // inside the imageGallery, the imageContainer that has a data-image_id attribute equal to the image id
    const imageContainer = imageGallery.querySelector('[data-image_id="' + image_id + '"]');

    // get dataset
    const dataset = Object.assign({}, imageContainer.dataset);

    // get ratio
    const ratio = parseFloat(dataset['ratio']);

    // get corners
    const tl_x = parseFloat(dataset['tl_x']);
    const tl_y = parseFloat(dataset['tl_y']);
    const tr_x = parseFloat(dataset['tr_x']);
    const tr_y = parseFloat(dataset['tr_y']);
    const br_x = parseFloat(dataset['br_x']);
    const br_y = parseFloat(dataset['br_y']);
    const bl_x = parseFloat(dataset['bl_x']);
    const bl_y = parseFloat(dataset['bl_y']);

    // assemble
    const corners = [
        [tl_x, tl_y],
        [tr_x, tr_y],
        [br_x, br_y],
        [bl_x, bl_y]
    ];

    // dimensions
    const width = THUMBNAIL_WIDTH / ratio;

    // rotate
    const corners_rotated = rotate90(width, corners);

    return corners_rotated;
}