<script>

    // import libs
    import { onMount } from 'svelte';
    import { reqGET } from '../../../meza-libraries/http/web/http.js';
    import { DEFAULT_SERVER, ENDPOINT_ACCOUNT, ENDPOINT_BRANCHES } from '../config.js';
    import { freeze, unfreeze } from '../../../meza-libraries/utils/web/svelte-stores.js';
    import { isObject, isNumber } from '../../../meza-libraries/gen/datatype.js';
    const server = DEFAULT_SERVER;

    // variables
    let ready = false;
    let branches = [];
    let headers = [];
    let values = [];

    // Map of access to roles
    const role_map = {
        '1': 'Admin',
        '2': 'Manager',
        '3': 'Employee',
        '4': 'Mobile App'
    }

    // Convert branch IDs to array
    const getSelectedBranchIds = (branchIdsString) => {
        return branchIdsString ? branchIdsString.split(',').map(id => parseInt(id, 10)) : [];
    };


    onMount(async () => {

        // load accounts
        freeze();
        const response = await reqGET(server, ENDPOINT_ACCOUNT);
        const response_branches = await reqGET(server, ENDPOINT_BRANCHES);
        unfreeze();

        // check for errors
        if (!isObject(response)){
            console.error('Error - http request failed');
            return;
        }

        // grab data
        const { status, data } = response;

        if (!isNumber(status) || +status !== 200){
            let message;
            try { message = data.message } catch(err) { message = 'http request failed' }
            console.error(`Error - ${message}`);
            return;
        }

        // Set branches
        branches = response_branches['data'].map(d => {
            return { 'id': d['id'], 'name': d['name'] }
        });
        const branches_map = {};
        branches.forEach(d => {
            branches_map[d['id']] = d['name'];
        });


        // Helper function to format the datetime returned by sql to yyyy-mm-dd
        const pad = (n) => {
            if (n < 10) return `0${n}`;
            return `${n}`;
        }
        const format_datetime = (datetime) => {
            if (datetime === null) return '';
            const date = new Date(datetime);
            const year = date.getFullYear();
            const month = pad(date.getMonth() + 1);
            const day = pad(date.getDate());

            return `${year}-${month}-${day}`;
        }
        const format_branch_ids = (branch_ids) => {
            if (branch_ids === null) return '';
            return branch_ids.map(d => branches_map[d]).join(', ');
        }

        // Convert array of dict to table
        headers = [ 'Email', 'Role', 'Branches', 'Last Login' ]
        values = data.map(d => {
            return [ d['email'], role_map[d['access']], format_branch_ids(d['branch_ids']), format_datetime(d['last_login_at']) ];
        })
        
        // Set ready
        ready = true;
    })

</script>


<!-- Accounts Table -->
<div class="container-table">
<table id="accountsTable">
    {#if ready}
    <thead>
        <tr class="header">
            {#each headers as header}
                <th>{header}</th>
            {/each}
        </tr>
    </thead>
    <tbody>
        <!-- Rows will be dynamically added here -->
        {#each values as row}
            <tr>
                <!-- Email -->
                <td>
                    {row[0]}
                </td>

                <!-- Roles -->
                <td>
                    {row[1].toString()}
                </td>

                <!-- Branches -->
                <td>
                    {row[2].toString()}
                </td>

                <!-- Last Login -->
                <td>
                    {row[3]}
                </td>

            </tr>
        {/each}
    </tbody>
    {/if}
</table>


</div>



